/**
 * Returns the average of cosine distances between vectors a and b
 * @param a - first vector
 * @param b - second vector
 *
 */
export function cosine(a: number[], b: number[]): number {
  let p = 0;
  let p2 = 0;
  let q2 = 0;
  for (let i = 0; i < a.length; i++) {
    p += a[i] * b[i];
    p2 += a[i] * a[i];
    q2 += b[i] * b[i];
  }
  return p / (Math.sqrt(p2) * Math.sqrt(q2));
}

import { cosine } from "./ml-distance/similarities.js";
import { innerProduct as innerProductDistance } from "./ml-distance/distances.js";
import { euclidean } from "./ml-distance-euclidean/euclidean.js";

type VectorFunction = (xVector: number[], yVector: number[]) => number;

/**
 * Apply a row-wise function between two matrices with the same number of columns.
 *
 * @param {number[][]} X - The first matrix.
 * @param {number[][]} Y - The second matrix.
 * @param {VectorFunction} func - The function to apply.
 *
 * @throws {Error} If the number of columns in X and Y are not the same.
 *
 * @returns {number[][] | [[]]} A matrix where each row represents the result of applying the function between the corresponding rows of X and Y.
 */

export function matrixFunc(
  X: number[][],
  Y: number[][],
  func: VectorFunction
): number[][] {
  if (
    X.length === 0 ||
    X[0].length === 0 ||
    Y.length === 0 ||
    Y[0].length === 0
  ) {
    return [[]];
  }

  if (X[0].length !== Y[0].length) {
    throw new Error(
      `Number of columns in X and Y must be the same. X has shape ${[
        X.length,
        X[0].length,
      ]} and Y has shape ${[Y.length, Y[0].length]}.`
    );
  }

  return X.map((xVector) =>
    Y.map((yVector) => func(xVector, yVector)).map((similarity) =>
      Number.isNaN(similarity) ? 0 : similarity
    )
  );
}

export function normalize(M: number[][], similarity = false): number[][] {
  const max = matrixMaxVal(M);
  return M.map((row) =>
    row.map((val) => (similarity ? 1 - val / max : val / max))
  );
}

/**
 * This function calculates the row-wise cosine similarity between two matrices with the same number of columns.
 *
 * @param {number[][]} X - The first matrix.
 * @param {number[][]} Y - The second matrix.
 *
 * @throws {Error} If the number of columns in X and Y are not the same.
 *
 * @returns {number[][] | [[]]} A matrix where each row represents the cosine similarity values between the corresponding rows of X and Y.
 */
export function cosineSimilarity(X: number[][], Y: number[][]): number[][] {
  return matrixFunc(X, Y, cosine);
}

export function innerProduct(X: number[][], Y: number[][]): number[][] {
  return matrixFunc(X, Y, innerProductDistance);
}

export function euclideanDistance(X: number[][], Y: number[][]): number[][] {
  return matrixFunc(X, Y, euclidean);
}

/**
 * This function implements the Maximal Marginal Relevance algorithm
 * to select a set of embeddings that maximizes the diversity and relevance to a query embedding.
 *
 * @param {number[]|number[][]} queryEmbedding - The query embedding.
 * @param {number[][]} embeddingList - The list of embeddings to select from.
 * @param {number} [lambda=0.5] - The trade-off parameter between relevance and diversity.
 * @param {number} [k=4] - The maximum number of embeddings to select.
 *
 * @returns {number[]} The indexes of the selected embeddings in the embeddingList.
 */
export function maximalMarginalRelevance(
  queryEmbedding: number[] | number[][],
  embeddingList: number[][],
  lambda = 0.5,
  k = 4
): number[] {
  if (Math.min(k, embeddingList.length) <= 0) {
    return [];
  }

  const queryEmbeddingExpanded = (
    Array.isArray(queryEmbedding[0]) ? queryEmbedding : [queryEmbedding]
  ) as number[][];

  const similarityToQuery = cosineSimilarity(
    queryEmbeddingExpanded,
    embeddingList
  )[0];
  const mostSimilarEmbeddingIndex = argMax(similarityToQuery).maxIndex;

  const selectedEmbeddings = [embeddingList[mostSimilarEmbeddingIndex]];
  const selectedEmbeddingsIndexes = [mostSimilarEmbeddingIndex];

  while (selectedEmbeddingsIndexes.length < Math.min(k, embeddingList.length)) {
    let bestScore = -Infinity;
    let bestIndex = -1;

    const similarityToSelected = cosineSimilarity(
      embeddingList,
      selectedEmbeddings
    );

    similarityToQuery.forEach((queryScore, queryScoreIndex) => {
      if (selectedEmbeddingsIndexes.includes(queryScoreIndex)) {
        return;
      }
      const maxSimilarityToSelected = Math.max(
        ...similarityToSelected[queryScoreIndex]
      );
      const score =
        lambda * queryScore - (1 - lambda) * maxSimilarityToSelected;

      if (score > bestScore) {
        bestScore = score;
        bestIndex = queryScoreIndex;
      }
    });
    selectedEmbeddings.push(embeddingList[bestIndex]);
    selectedEmbeddingsIndexes.push(bestIndex);
  }

  return selectedEmbeddingsIndexes;
}

type MaxInfo = {
  maxIndex: number;
  maxValue: number;
};

/**
 * Finds the index of the maximum value in the given array.
 * @param {number[]} array - The input array.
 *
 * @returns {number} The index of the maximum value in the array. If the array is empty, returns -1.
 */
function argMax(array: number[]): MaxInfo {
  if (array.length === 0) {
    return {
      maxIndex: -1,
      maxValue: NaN,
    };
  }

  let maxValue = array[0];
  let maxIndex = 0;

  for (let i = 1; i < array.length; i += 1) {
    if (array[i] > maxValue) {
      maxIndex = i;
      maxValue = array[i];
    }
  }
  return { maxIndex, maxValue };
}

function matrixMaxVal(arrays: number[][]): number {
  return arrays.reduce(
    (acc, array) => Math.max(acc, argMax(array).maxValue),
    0
  );
}

import snakeCase from "decamelize";
import camelCase from "camelcase";

export interface SerializedFields {
  // eslint-disable-next-line @typescript-eslint/no-explicit-any
  [key: string]: any;
}

export interface SerializedKeyAlias {
  [key: string]: string;
}

export function keyToJson(key: string, map?: SerializedKeyAlias): string {
  return map?.[key] || snakeCase(key);
}

export function keyFromJson(key: string, map?: SerializedKeyAlias): string {
  return map?.[key] || camelCase(key);
}

export function mapKeys(
  fields: SerializedFields,
  mapper: typeof keyToJson,
  map?: SerializedKeyAlias
): SerializedFields {
  const mapped: SerializedFields = {};

  for (const key in fields) {
    if (Object.hasOwn(fields, key)) {
      mapped[mapper(key, map)] = fields[key];
    }
  }

  return mapped;
}

/**
 * Sentinel key used to mark escaped user objects during serialization.
 *
 * When a plain object contains 'lc' key (which could be confused with LC objects),
 * we wrap it as `{"__lc_escaped__": {...original...}}`.
 */
export const LC_ESCAPED_KEY = "__lc_escaped__";

/**
 * Check if an object needs escaping to prevent confusion with LC objects.
 *
 * An object needs escaping if:
 * 1. It has an `'lc'` key (could be confused with LC serialization format)
 * 2. It has only the escape key (would be mistaken for an escaped object)
 */
export function needsEscaping(obj: Record<string, unknown>): boolean {
  return (
    "lc" in obj || (Object.keys(obj).length === 1 && LC_ESCAPED_KEY in obj)
  );
}

/**
 * Wrap an object in the escape marker.
 *
 * @example
 * ```typescript
 * {"key": "value"}  // becomes {"__lc_escaped__": {"key": "value"}}
 * ```
 */
export function escapeObject(
  obj: Record<string, unknown>
): Record<string, unknown> {
  return { [LC_ESCAPED_KEY]: obj };
}

/**
 * Check if an object is an escaped user object.
 *
 * @example
 * ```typescript
 * {"__lc_escaped__": {...}}  // is an escaped object
 * ```
 */
export function isEscapedObject(obj: Record<string, unknown>): boolean {
  return Object.keys(obj).length === 1 && LC_ESCAPED_KEY in obj;
}

/**
 * Interface for objects that can be serialized.
 * This is a duck-typed interface to avoid circular imports.
 */
interface SerializableLike {
  lc_serializable: boolean;
  lc_secrets?: Record<string, string>;
  toJSON(): {
    lc: number;
    type: string;
    id: string[];
    kwargs?: Record<string, unknown>;
  };
}

/**
 * Check if an object looks like a Serializable instance (duck typing).
 */
function isSerializableLike(obj: unknown): obj is SerializableLike {
  return (
    obj !== null &&
    typeof obj === "object" &&
    "lc_serializable" in obj &&
    typeof (obj as SerializableLike).toJSON === "function"
  );
}

/**
 * Create a "not_implemented" serialization result for objects that cannot be serialized.
 */
function createNotImplemented(obj: unknown): {
  lc: 1;
  type: "not_implemented";
  id: string[];
} {
  let id: string[];
  if (obj !== null && typeof obj === "object") {
    if ("lc_id" in obj && Array.isArray(obj.lc_id)) {
      id = obj.lc_id as string[];
    } else {
      id = [obj.constructor?.name ?? "Object"];
    }
  } else {
    id = [typeof obj];
  }
  return {
    lc: 1,
    type: "not_implemented",
    id,
  };
}

/**
 * Serialize a value with escaping of user objects.
 *
 * Called recursively on kwarg values to escape any plain objects that could be
 * confused with LC objects.
 *
 * @param obj - The value to serialize.
 * @param pathSet - WeakSet to track ancestor objects in the current path to detect circular references.
 *                  Objects are removed after processing to allow shared references (same object in
 *                  multiple places) while still detecting true circular references (ancestor in descendant).
 * @returns The serialized value with user objects escaped as needed.
 */
export function serializeValue(
  obj: unknown,
  pathSet: WeakSet<object> = new WeakSet()
): unknown {
  if (obj !== null && typeof obj === "object" && !Array.isArray(obj)) {
    // Check for circular reference - only if this object is an ancestor in the current path
    if (pathSet.has(obj)) {
      return createNotImplemented(obj);
    }

    if (isSerializableLike(obj)) {
      // This is an LC object - serialize it properly (not escaped)
      return serializeLcObject(obj, pathSet);
    }

    // Add to path before processing children
    pathSet.add(obj);

    const record = obj as Record<string, unknown>;
    // Check if object needs escaping BEFORE recursing into values.
    // If it needs escaping, wrap it as-is - the contents are user data that
    // will be returned as-is during deserialization (no instantiation).
    // This prevents re-escaping of already-escaped nested content.
    if (needsEscaping(record)) {
      // Remove from path before returning (to allow shared references)
      pathSet.delete(obj);
      return escapeObject(record);
    }
    // Safe object (no 'lc' key) - recurse into values
    const result: Record<string, unknown> = {};
    for (const [key, value] of Object.entries(record)) {
      result[key] = serializeValue(value, pathSet);
    }
    // Remove from path after processing (to allow shared references in other branches)
    pathSet.delete(obj);
    return result;
  }

  if (Array.isArray(obj)) {
    // Arrays don't need circular reference tracking since they're handled by object tracking
    return obj.map((item) => serializeValue(item, pathSet));
  }

  if (
    typeof obj === "string" ||
    typeof obj === "number" ||
    typeof obj === "boolean" ||
    obj === null
  ) {
    return obj;
  }

  // Non-JSON-serializable object (Date, custom objects, etc.)
  return createNotImplemented(obj);
}

/**
 * Serialize a `Serializable` object with escaping of user data in kwargs.
 *
 * @param obj - The `Serializable` object to serialize.
 * @param pathSet - WeakSet to track ancestor objects in the current path to detect circular references.
 *                  The Serializable object is kept in the path set to detect if it appears in its own kwargs.
 * @returns The serialized object with user data in kwargs escaped as needed.
 *
 * @remarks
 * Kwargs values are processed with `serializeValue` to escape user data (like
 * metadata) that contains `'lc'` keys. Secret fields (from `lc_secrets`) are
 * skipped because `toJSON()` replaces their values with secret markers.
 */
export function serializeLcObject(
  obj: SerializableLike,
  pathSet: WeakSet<object> = new WeakSet()
): {
  lc: number;
  type: string;
  id: string[];
  kwargs?: Record<string, unknown>;
} {
  // Add object to path set to detect if it appears in its own kwargs (circular reference)
  // Note: We intentionally don't remove this after processing because a Serializable
  // appearing in its own kwargs is always a circular reference that should be detected.
  pathSet.add(obj);

  // Secret fields are handled by toJSON() - it replaces values with secret markers
  const secretFields = new Set(Object.keys(obj.lc_secrets ?? {}));

  const serialized = { ...obj.toJSON() };

  // Process kwargs to escape user data that could be confused with LC objects
  // Skip secret fields - toJSON() already converted them to secret markers
  if (serialized.type === "constructor" && serialized.kwargs) {
    const newKwargs: Record<string, unknown> = {};
    for (const [key, value] of Object.entries(serialized.kwargs)) {
      if (secretFields.has(key)) {
        newKwargs[key] = value;
      } else {
        newKwargs[key] = serializeValue(value, pathSet);
      }
    }
    serialized.kwargs = newKwargs;
  }

  return serialized;
}

/**
 * Escape a value if it needs escaping (contains `lc` key).
 *
 * This is a simpler version of `serializeValue` that doesn't handle Serializable
 * objects - it's meant to be called on kwargs values that have already been
 * processed by `toJSON()`.
 *
 * @param value - The value to potentially escape.
 * @param pathSet - WeakSet to track ancestor objects in the current path to detect circular references.
 *                  Objects are removed after processing to allow shared references (same object in
 *                  multiple places) while still detecting true circular references (ancestor in descendant).
 * @returns The value with any `lc`-containing objects wrapped in escape markers.
 */
export function escapeIfNeeded(
  value: unknown,
  pathSet: WeakSet<object> = new WeakSet()
): unknown {
  if (value !== null && typeof value === "object" && !Array.isArray(value)) {
    // Check for circular reference - only if this object is an ancestor in the current path
    if (pathSet.has(value)) {
      // Replace circular reference with a not_implemented marker
      return createNotImplemented(value);
    }

    // Preserve Serializable objects - they have their own toJSON() that will be
    // called by JSON.stringify. We don't want to convert them to plain objects.
    if (isSerializableLike(value)) {
      return value;
    }

    // Add to path before processing children
    pathSet.add(value);

    const record = value as Record<string, unknown>;
    // Check if object needs escaping BEFORE recursing into values.
    // If it needs escaping, wrap it as-is - the contents are user data that
    // will be returned as-is during deserialization (no instantiation).
    if (needsEscaping(record)) {
      // Remove from path before returning (to allow shared references)
      pathSet.delete(value);
      return escapeObject(record);
    }
    // Safe object (no 'lc' key) - recurse into values
    const result: Record<string, unknown> = {};
    for (const [key, val] of Object.entries(record)) {
      result[key] = escapeIfNeeded(val, pathSet);
    }
    // Remove from path after processing (to allow shared references in other branches)
    pathSet.delete(value);
    return result;
  }

  if (Array.isArray(value)) {
    return value.map((item) => escapeIfNeeded(item, pathSet));
  }

  return value;
}

/**
 * Unescape a value, processing escape markers in object values and arrays.
 *
 * When an escaped object is encountered (`{"__lc_escaped__": ...}`), it's
 * unwrapped and the contents are returned AS-IS (no further processing).
 * The contents represent user data that should not be modified.
 *
 * For regular objects and arrays, we recurse to find any nested escape markers.
 *
 * @param obj - The value to unescape.
 * @returns The unescaped value.
 */
export function unescapeValue(obj: unknown): unknown {
  if (obj !== null && typeof obj === "object" && !Array.isArray(obj)) {
    const record = obj as Record<string, unknown>;
    if (isEscapedObject(record)) {
      // Unwrap and return the user data as-is (no further unescaping).
      // The contents are user data that may contain more escape keys,
      // but those are part of the user's actual data.
      return record[LC_ESCAPED_KEY];
    }

    // Regular object - recurse into values to find nested escape markers
    const result: Record<string, unknown> = {};
    for (const [key, value] of Object.entries(record)) {
      result[key] = unescapeValue(value);
    }
    return result;
  }

  if (Array.isArray(obj)) {
    return obj.map((item) => unescapeValue(item));
  }

  return obj;
}

import type { ContentBlock } from "../content/index.js";

export function _isContentBlock<T extends string>(
  block: unknown,
  type: T
): block is ContentBlock & { type: T } {
  return _isObject(block) && block.type === type;
}

export function _isObject(value: unknown): value is Record<string, unknown> {
  return typeof value === "object" && value !== null;
}

export function _isArray<T>(value: unknown): value is T[] {
  return Array.isArray(value);
}

export function _isString(value: unknown): value is string {
  return typeof value === "string";
}

export function _isNumber(value: unknown): value is number {
  return typeof value === "number";
}

export function _isBytesArray(value: unknown): value is Uint8Array {
  // eslint-disable-next-line no-instanceof/no-instanceof
  return value instanceof Uint8Array;
}

export function safeParseJson<T = unknown>(value: string): T | undefined {
  try {
    return JSON.parse(value);
  } catch {
    return undefined;
  }
}

export const iife = <T>(fn: () => T): T => fn();

import { AIMessage } from "../ai.js";
import { ContentBlock } from "../content/index.js";
import { KNOWN_BLOCK_TYPES } from "../content/tools.js";
import type { StandardContentBlockTranslator } from "./index.js";
import {
  _isArray,
  _isBytesArray,
  _isContentBlock,
  _isNumber,
  _isObject,
  _isString,
  iife,
} from "./utils.js";

// see `/libs/providers/langchain-aws/src/utils/compat.ts:convertFileFormatToMimeType`
function convertFileFormatToMimeType(format: string): string {
  switch (format) {
    // DocumentBlock
    case "csv":
      return "text/csv";
    case "doc":
      return "application/vnd.openxmlformats-officedocument.wordprocessingml.document";
    case "docx":
      return "application/vnd.openxmlformats-officedocument.wordprocessingml.document";
    case "html":
      return "text/html";
    case "md":
      return "text/markdown";
    case "pdf":
      return "application/pdf";
    case "txt":
      return "text/plain";
    case "xls":
      return "application/vnd.ms-excel";
    case "xlsx":
      return "application/vnd.openxmlformats-officedocument.spreadsheetml.sheet";
    // ImageBlock
    case "gif":
      return "image/gif";
    case "jpeg":
      return "image/jpeg";
    case "jpg":
      return "image/jpeg";
    case "png":
      return "image/png";
    case "webp":
      return "image/webp";
    // VideoBlock
    case "flv":
      return "video/flv";
    case "mkv":
      return "video/mkv";
    case "mov":
      return "video/mov";
    case "mp4":
      return "video/mp4";
    case "mpeg":
      return "video/mpeg";
    case "mpg":
      return "video/mpg";
    case "three_gp":
      return "video/three_gp";
    case "webm":
      return "video/webm";
    case "wmv":
      return "video/wmv";
    default:
      return "application/octet-stream";
  }
}

function convertConverseDocumentBlock(
  block: ContentBlock
): ContentBlock.Standard {
  if (_isObject(block.document) && _isObject(block.document.source)) {
    const format =
      _isObject(block.document) && _isString(block.document.format)
        ? block.document.format
        : "";
    const mimeType = convertFileFormatToMimeType(format);

    if (_isObject(block.document.source)) {
      if (
        _isObject(block.document.source.s3Location) &&
        _isString(block.document.source.s3Location.uri)
      ) {
        return {
          type: "file",
          mimeType,
          fileId: block.document.source.s3Location.uri,
        };
      }
      if (_isBytesArray(block.document.source.bytes)) {
        return {
          type: "file",
          mimeType,
          data: block.document.source.bytes,
        };
      }
      if (_isString(block.document.source.text)) {
        return {
          type: "file",
          mimeType,
          data: Buffer.from(block.document.source.text).toString("base64"),
        };
      }
      if (_isArray(block.document.source.content)) {
        const data = block.document.source.content.reduce(
          (acc: string, item) => {
            if (_isObject(item) && _isString(item.text)) {
              return acc + item.text;
            }
            return acc;
          },
          ""
        );
        return {
          type: "file",
          mimeType,
          data,
        };
      }
    }
  }
  return { type: "non_standard", value: block };
}

function convertConverseImageBlock(block: ContentBlock): ContentBlock.Standard {
  if (_isContentBlock(block, "image") && _isObject(block.image)) {
    const format =
      _isObject(block.image) && _isString(block.image.format)
        ? block.image.format
        : "";
    const mimeType = convertFileFormatToMimeType(format);

    if (_isObject(block.image.source)) {
      if (
        _isObject(block.image.source.s3Location) &&
        _isString(block.image.source.s3Location.uri)
      ) {
        return {
          type: "image",
          mimeType,
          fileId: block.image.source.s3Location.uri,
        };
      }
      if (_isBytesArray(block.image.source.bytes)) {
        return {
          type: "image",
          mimeType,
          data: block.image.source.bytes,
        };
      }
    }
  }
  return { type: "non_standard", value: block };
}

function convertConverseVideoBlock(block: ContentBlock): ContentBlock.Standard {
  if (_isContentBlock(block, "video") && _isObject(block.video)) {
    const format =
      _isObject(block.video) && _isString(block.video.format)
        ? block.video.format
        : "";
    const mimeType = convertFileFormatToMimeType(format);

    if (_isObject(block.video.source)) {
      if (
        _isObject(block.video.source.s3Location) &&
        _isString(block.video.source.s3Location.uri)
      ) {
        return {
          type: "video",
          mimeType,
          fileId: block.video.source.s3Location.uri,
        };
      }
      if (_isBytesArray(block.video.source.bytes)) {
        return {
          type: "video",
          mimeType,
          data: block.video.source.bytes,
        };
      }
    }
  }
  return { type: "non_standard", value: block };
}

export function convertToV1FromChatBedrockConverseInput(
  message: AIMessage
): Array<ContentBlock.Standard> {
  function* iterateContent(): Iterable<ContentBlock.Standard> {
    const content =
      typeof message.content === "string"
        ? [{ type: "text", text: message.content }]
        : message.content;
    const blocks = content.map((block) => {
      if (_isContentBlock(block, "non_standard") && "value" in block) {
        return block.value as ContentBlock;
      }
      return block;
    });
    for (const block of blocks) {
      if (_isContentBlock(block, "text") && _isString(block.text)) {
        yield { type: "text", text: block.text };
        continue;
      } else if (
        _isContentBlock(block, "document") &&
        _isObject(block.document)
      ) {
        yield convertConverseDocumentBlock(block);
        continue;
      } else if (_isContentBlock(block, "image") && _isObject(block.image)) {
        yield convertConverseImageBlock(block);
        continue;
      } else if (_isContentBlock(block, "video") && _isObject(block.video)) {
        yield convertConverseVideoBlock(block);
        continue;
      }
      if (KNOWN_BLOCK_TYPES.includes(block.type)) {
        yield block as ContentBlock.Standard;
      } else {
        yield { type: "non_standard", value: block };
      }
    }
  }
  return Array.from(iterateContent());
}

function convertToV1FromChatBedrockConverseMessage(
  message: AIMessage
): Array<ContentBlock.Standard> {
  // see `/libs/providers/langchain-aws/src/utils/message_outputs.ts:convertConverseMessageToLangChainMessage`
  function* iterateContent(): Iterable<ContentBlock.Standard> {
    const content =
      typeof message.content === "string"
        ? [{ type: "text", text: message.content }]
        : message.content;
    for (const block of content) {
      if (_isContentBlock(block, "cache_point")) {
        yield { type: "non_standard", value: block };
        continue;
      } else if (
        _isContentBlock(block, "citations_content") &&
        _isObject(block.citationsContent)
      ) {
        const text = _isArray(block.citationsContent.content)
          ? block.citationsContent.content.reduce((acc: string, item) => {
              if (_isObject(item) && _isString(item.text)) {
                return acc + item.text;
              }
              return acc;
            }, "")
          : "";
        const annotations = _isArray(block.citationsContent.citations)
          ? block.citationsContent.citations.reduce(
              (acc: Array<ContentBlock.Citation>, item) => {
                if (_isObject(item)) {
                  const citedText = _isArray(item.sourceContent)
                    ? item.sourceContent.reduce((acc: string, item) => {
                        if (_isObject(item) && _isString(item.text)) {
                          return acc + item.text;
                        }
                        return acc;
                      }, "")
                    : "";
                  const properties = iife(() => {
                    if (_isObject(item.location)) {
                      const location =
                        item.location.documentChar ||
                        item.location.documentPage ||
                        item.location.documentChunk;
                      if (_isObject(location)) {
                        return {
                          source: _isNumber(location.documentIndex)
                            ? location.documentIndex.toString()
                            : undefined,
                          startIndex: _isNumber(location.start)
                            ? location.start
                            : undefined,
                          endIndex: _isNumber(location.end)
                            ? location.end
                            : undefined,
                        };
                      }
                    }
                    return {};
                  });
                  acc.push({ type: "citation", citedText, ...properties });
                }
                return acc;
              },
              []
            )
          : [];
        yield { type: "text", text, annotations };
        continue;
      } else if (
        _isContentBlock(block, "document") &&
        _isObject(block.document)
      ) {
        yield convertConverseDocumentBlock(block);
        continue;
      } else if (_isContentBlock(block, "guard_content")) {
        yield {
          type: "non_standard",
          value: block,
        };
        continue;
      } else if (_isContentBlock(block, "image") && _isObject(block.image)) {
        yield convertConverseImageBlock(block);
        continue;
      } else if (
        _isContentBlock(block, "reasoning_content") &&
        _isString(block.reasoningText)
      ) {
        yield {
          type: "reasoning",
          reasoning: block.reasoningText,
        };
        continue;
      } else if (_isContentBlock(block, "text") && _isString(block.text)) {
        yield { type: "text", text: block.text };
        continue;
      } else if (_isContentBlock(block, "tool_result")) {
        yield { type: "non_standard", value: block };
        continue;
      } else if (_isContentBlock(block, "tool_call")) {
        // no-op - filtered to tools
        continue;
      } else if (_isContentBlock(block, "video") && _isObject(block.video)) {
        yield convertConverseVideoBlock(block);
        continue;
      }
      yield { type: "non_standard", value: block };
    }
  }
  return Array.from(iterateContent());
}

export const ChatBedrockConverseTranslator: StandardContentBlockTranslator = {
  translateContent: convertToV1FromChatBedrockConverseMessage,
  translateContentChunk: convertToV1FromChatBedrockConverseMessage,
};

import { AIMessage } from "../ai.js";
import { ContentBlock } from "../content/index.js";
import type { StandardContentBlockTranslator } from "./index.js";
import { _isString } from "./utils.js";

/**
 * Converts a DeepSeek AI message to an array of v1 standard content blocks.
 *
 * This function processes an AI message from DeepSeek's API format
 * and converts it to the standardized v1 content block format. It handles
 * both string content and the reasoning_content in additional_kwargs.
 *
 * @param message - The AI message containing DeepSeek-formatted content
 * @returns Array of content blocks in v1 standard format
 *
 * @example
 * ```typescript
 * const message = new AIMessage({
 *   content: "The answer is 42",
 *   additional_kwargs: { reasoning_content: "Let me think about this..." }
 * });
 * const standardBlocks = convertToV1FromDeepSeekMessage(message);
 * // Returns:
 * // [
 * //   { type: "reasoning", reasoning: "Let me think about this..." },
 * //   { type: "text", text: "The answer is 42" }
 * // ]
 * ```
 */
export function convertToV1FromDeepSeekMessage(
  message: AIMessage
): Array<ContentBlock.Standard> {
  const blocks: Array<ContentBlock.Standard> = [];

  // Extract reasoning from additional_kwargs.reasoning_content
  const reasoningContent = message.additional_kwargs?.reasoning_content;
  if (_isString(reasoningContent) && reasoningContent.length > 0) {
    blocks.push({
      type: "reasoning",
      reasoning: reasoningContent,
    });
  }

  // Handle text content
  if (typeof message.content === "string") {
    if (message.content.length > 0) {
      blocks.push({
