export const RUN_KEY = "__run";

/**
 * Output of a single generation.
 */
export interface Generation {
  /**
   * Generated text output
   */
  text: string;
  /**
   * Raw generation info response from the provider.
   * May include things like reason for finishing (e.g. in {@link OpenAI})
   */
  // eslint-disable-next-line @typescript-eslint/no-explicit-any
  generationInfo?: Record<string, any>;
}

export type GenerationChunkFields = {
  text: string;
  // eslint-disable-next-line @typescript-eslint/no-explicit-any
  generationInfo?: Record<string, any>;
};

/**
 * Chunk of a single generation. Used for streaming.
 */
export class GenerationChunk implements Generation {
  public text: string;

  // eslint-disable-next-line @typescript-eslint/no-explicit-any
  public generationInfo?: Record<string, any>;

  constructor(fields: GenerationChunkFields) {
    this.text = fields.text;
    this.generationInfo = fields.generationInfo;
  }

  concat(chunk: GenerationChunk): GenerationChunk {
    return new GenerationChunk({
      text: this.text + chunk.text,
      generationInfo: {
        ...this.generationInfo,
        ...chunk.generationInfo,
      },
    });
  }
}

/**
 * Contains all relevant information returned by an LLM.
 */
export type LLMResult = {
  /**
   * List of the things generated. Each input could have multiple {@link Generation | generations}, hence this is a list of lists.
   */
  generations: Generation[][];
  /**
   * Dictionary of arbitrary LLM-provider specific output.
   */
  // eslint-disable-next-line @typescript-eslint/no-explicit-any
  llmOutput?: Record<string, any>;
  /**
   * Dictionary of run metadata
   */
  // eslint-disable-next-line @typescript-eslint/no-explicit-any
  [RUN_KEY]?: Record<string, any>;
};

export interface ChatGeneration extends Generation {
  message: BaseMessage;
}

export type ChatGenerationChunkFields = GenerationChunkFields & {
  message: BaseMessageChunk;
};

export class ChatGenerationChunk
  extends GenerationChunk
  implements ChatGeneration
{
  public message: BaseMessageChunk;

  constructor(fields: ChatGenerationChunkFields) {
    super(fields);
    this.message = fields.message;
  }

  concat(chunk: ChatGenerationChunk) {
    return new ChatGenerationChunk({
      text: this.text + chunk.text,
      generationInfo: {
        ...this.generationInfo,
        ...chunk.generationInfo,
      },
      message: this.message.concat(chunk.message),
    });
  }
}

export interface ChatResult {
  generations: ChatGeneration[];

  // eslint-disable-next-line @typescript-eslint/no-explicit-any
  llmOutput?: Record<string, any>;
}

/* eslint-disable */
const objectToString = Object.prototype.toString;

const isError = (value) => objectToString.call(value) === "[object Error]";

const errorMessages = new Set([
  "network error", // Chrome
  "Failed to fetch", // Chrome
  "NetworkError when attempting to fetch resource.", // Firefox
  "The Internet connection appears to be offline.", // Safari 16
  "Network request failed", // `cross-fetch`
  "fetch failed", // Undici (Node.js)
  "terminated", // Undici (Node.js)
  " A network error occurred.", // Bun (WebKit)
  "Network connection lost", // Cloudflare Workers (fetch)
]);

export default function isNetworkError(error) {
  const isValid =
    error &&
    isError(error) &&
    error.name === "TypeError" &&
    typeof error.message === "string";

  if (!isValid) {
    return false;
  }

  const { message, stack } = error;

  // Safari 17+ has generic message but no stack for network errors
  if (message === "Load failed") {
    return (
      stack === undefined ||
      // Sentry adds its own stack trace to the fetch error, so also check for that
      "__sentry_captured__" in error
    );
  }

  // Deno network errors start with specific text
  if (message.startsWith("error sending request for url")) {
    return true;
  }

  // Standard network error messages
  return errorMessages.has(message);
}

import { Edge, Node } from "./types.js";
import { toBase64Url } from "./utils.js";

function _escapeNodeLabel(nodeLabel: string): string {
  // Escapes the node label for Mermaid syntax.
  return nodeLabel.replace(/[^a-zA-Z-_0-9]/g, "_");
}

const MARKDOWN_SPECIAL_CHARS = ["*", "_", "`"];

function _generateMermaidGraphStyles(
  nodeColors: Record<string, string>
): string {
  let styles = "";
  for (const [className, color] of Object.entries(nodeColors)) {
    styles += `\tclassDef ${className} ${color};\n`;
  }
  return styles;
}

/**
 * Draws a Mermaid graph using the provided graph data
 */
export function drawMermaid(
  nodes: Record<string, Node>,
  edges: Edge[],
  config?: {
    firstNode?: string;
    lastNode?: string;
    curveStyle?: string;
    withStyles?: boolean;
    nodeColors?: Record<string, string>;
    wrapLabelNWords?: number;
  }
): string {
  const {
    firstNode,
    lastNode,
    nodeColors,
    withStyles = true,
    curveStyle = "linear",
    wrapLabelNWords = 9,
  } = config ?? {};
  // Initialize Mermaid graph configuration
  let mermaidGraph = withStyles
    ? `%%{init: {'flowchart': {'curve': '${curveStyle}'}}}%%\ngraph TD;\n`
    : "graph TD;\n";
  if (withStyles) {
    // Node formatting templates
    const defaultClassLabel = "default";
    const formatDict: Record<string, string> = {
      [defaultClassLabel]: "{0}({1})",
    };
    if (firstNode !== undefined) {
      formatDict[firstNode] = "{0}([{1}]):::first";
    }
    if (lastNode !== undefined) {
      formatDict[lastNode] = "{0}([{1}]):::last";
    }

    // Add nodes to the graph
    for (const [key, node] of Object.entries(nodes)) {
      const nodeName = node.name.split(":").pop() ?? "";
      const label = MARKDOWN_SPECIAL_CHARS.some(
        (char) => nodeName.startsWith(char) && nodeName.endsWith(char)
      )
        ? `<p>${nodeName}</p>`
        : nodeName;

      let finalLabel = label;
      if (Object.keys(node.metadata ?? {}).length) {
        finalLabel += `<hr/><small><em>${Object.entries(node.metadata ?? {})
          .map(([k, v]) => `${k} = ${v}`)
          .join("\n")}</em></small>`;
      }

      const nodeLabel = (formatDict[key] ?? formatDict[defaultClassLabel])
        .replace("{0}", _escapeNodeLabel(key))
        .replace("{1}", finalLabel);

      mermaidGraph += `\t${nodeLabel}\n`;
    }
  }

  // Group edges by their common prefixes
  const edgeGroups: Record<string, Edge[]> = {};
  for (const edge of edges) {
    const srcParts = edge.source.split(":");
    const tgtParts = edge.target.split(":");
    const commonPrefix = srcParts
      .filter((src, i) => src === tgtParts[i])
      .join(":");
    if (!edgeGroups[commonPrefix]) {
      edgeGroups[commonPrefix] = [];
    }
    edgeGroups[commonPrefix].push(edge);
  }

  const seenSubgraphs = new Set<string>();

  // sort prefixes by path length for correct nesting
  function sortPrefixesByDepth(prefixes: string[]): string[] {
    return [...prefixes].sort((a, b) => {
      return a.split(":").length - b.split(":").length;
    });
  }

  function addSubgraph(edges: Edge[], prefix: string): void {
    const selfLoop = edges.length === 1 && edges[0].source === edges[0].target;
    if (prefix && !selfLoop) {
      const subgraph = prefix.split(":").pop()!;

      if (seenSubgraphs.has(prefix)) {
        throw new Error(
          `Found duplicate subgraph '${subgraph}' at '${prefix} -- this likely means that ` +
            "you're reusing a subgraph node with the same name. " +
            "Please adjust your graph to have subgraph nodes with unique names."
        );
      }

      seenSubgraphs.add(prefix);
      mermaidGraph += `\tsubgraph ${subgraph}\n`;
    }

    // all nested prefixes for this level, sorted by depth
    const nestedPrefixes = sortPrefixesByDepth(
      Object.keys(edgeGroups).filter(
        (nestedPrefix) =>
          nestedPrefix.startsWith(`${prefix}:`) &&
          nestedPrefix !== prefix &&
          nestedPrefix.split(":").length === prefix.split(":").length + 1
      )
    );

    for (const nestedPrefix of nestedPrefixes) {
      addSubgraph(edgeGroups[nestedPrefix], nestedPrefix);
    }

    for (const edge of edges) {
      const { source, target, data, conditional } = edge;

      let edgeLabel = "";
      if (data !== undefined) {
        let edgeData = data;
        const words = edgeData.split(" ");
        if (words.length > wrapLabelNWords) {
          edgeData = Array.from(
            { length: Math.ceil(words.length / wrapLabelNWords) },
            (_, i) =>
              words
                .slice(i * wrapLabelNWords, (i + 1) * wrapLabelNWords)
                .join(" ")
          ).join("&nbsp;<br>&nbsp;");
        }
        edgeLabel = conditional
          ? ` -. &nbsp;${edgeData}&nbsp; .-> `
          : ` -- &nbsp;${edgeData}&nbsp; --> `;
      } else {
        edgeLabel = conditional ? " -.-> " : " --> ";
      }

      mermaidGraph += `\t${_escapeNodeLabel(
        source
      )}${edgeLabel}${_escapeNodeLabel(target)};\n`;
    }

    if (prefix && !selfLoop) {
      mermaidGraph += "\tend\n";
    }
  }

  // Start with the top-level edges (no common prefix)
  addSubgraph(edgeGroups[""] ?? [], "");

  // Add remaining top-level subgraphs
  for (const prefix in edgeGroups) {
    if (!prefix.includes(":") && prefix !== "") {
      addSubgraph(edgeGroups[prefix], prefix);
    }
  }

  // Add custom styles for nodes
  if (withStyles) {
    mermaidGraph += _generateMermaidGraphStyles(nodeColors ?? {});
  }

  return mermaidGraph;
}

/**
 * Renders Mermaid graph using the Mermaid.INK API.
 *
 * @example
 * ```javascript
 * const image = await drawMermaidImage(mermaidSyntax, {
 *   backgroundColor: "white",
 *   imageType: "png",
 * });
 * fs.writeFileSync("image.png", image);
 * ```
 *
 * @param mermaidSyntax - The Mermaid syntax to render.
 * @param config - The configuration for the image.
 * @returns The image as a Blob.
 */
export async function drawMermaidImage(
  mermaidSyntax: string,
  config?: {
    /**
     * The type of image to render.
     * @default "png"
     */
    imageType?: "png" | "jpeg" | "webp";
    backgroundColor?: string;
  }
) {
  let backgroundColor = config?.backgroundColor ?? "white";
  const imageType = config?.imageType ?? "png";

  const mermaidSyntaxEncoded = toBase64Url(mermaidSyntax);

  // Check if the background color is a hexadecimal color code using regex
  if (backgroundColor !== undefined) {
    const hexColorPattern = /^#(?:[0-9a-fA-F]{3}){1,2}$/;
    if (!hexColorPattern.test(backgroundColor)) {
      backgroundColor = `!${backgroundColor}`;
    }
  }
  const imageUrl = `https://mermaid.ink/img/${mermaidSyntaxEncoded}?bgColor=${backgroundColor}&type=${imageType}`;
  const res = await fetch(imageUrl);
  if (!res.ok) {
    throw new Error(
      [
        `Failed to render the graph using the Mermaid.INK API.`,
        `Status code: ${res.status}`,
        `Status text: ${res.statusText}`,
      ].join("\n")
    );
  }
  const content = await res.blob();
  return content;
}

import { toJSONSchema } from "zod/v4/core";
import { dereference, type Schema } from "@cfworker/json-schema";
import {
  isZodSchemaV3,
  isZodSchemaV4,
  InteropZodType,
  interopZodObjectStrict,
  isZodObjectV4,
  ZodObjectV4,
  interopZodTransformInputSchema,
} from "./types/zod.js";
import {
  type JsonSchema7Type as JSONSchema,
  zodToJsonSchema,
} from "./zod-to-json-schema/index.js";
import { StandardJSONSchemaV1 } from "@standard-schema/spec";
import { isStandardJsonSchema } from "./standard_schema.js";

export { deepCompareStrict, Validator } from "@cfworker/json-schema";

export type ToJSONSchemaParams = NonNullable<
  Parameters<typeof toJSONSchema>[1]
>;

/**
 * Converts a Standard JSON schema, Zod schema or JSON schema to a JSON schema.
 * @param schema - The schema to convert.
 * @param params - The parameters to pass to the toJSONSchema function.
 * @returns The converted schema.
 */
export function toJsonSchema(
  schema: StandardJSONSchemaV1 | InteropZodType | JSONSchema,
  params?: ToJSONSchemaParams
): JSONSchema {
  if (isStandardJsonSchema(schema) && !isZodSchemaV4(schema)) {
    return schema["~standard"].jsonSchema.input({
      target: "draft-07",
    }) as JSONSchema;
  }
  if (isZodSchemaV4(schema)) {
    const inputSchema = interopZodTransformInputSchema(schema, true);
    if (isZodObjectV4(inputSchema)) {
      const strictSchema = interopZodObjectStrict(
        inputSchema,
        true
      ) as ZodObjectV4;
      return toJSONSchema(strictSchema, params);
    } else {
      return toJSONSchema(schema, params);
    }
  }
  if (isZodSchemaV3(schema)) {
    return zodToJsonSchema(schema);
  }
  return schema as JSONSchema;
}

/**
 * Validates if a JSON schema validates only strings. May return false negatives in some edge cases
 * (like recursive or unresolvable refs).
 *
 * @param schema - The schema to validate.
 * @returns `true` if the schema validates only strings, `false` otherwise.
 */
export function validatesOnlyStrings(schema: unknown): boolean {
  // Null, undefined, or empty schema
  if (
    !schema ||
    typeof schema !== "object" ||
    Object.keys(schema).length === 0 ||
    Array.isArray(schema)
  ) {
    return false; // Validates anything, not just strings
  }

  // Explicit type constraint
  if ("type" in schema) {
    if (typeof schema.type === "string") {
      return schema.type === "string";
    }

    if (Array.isArray(schema.type)) {
      // not sure why someone would do `"type": ["string"]` or especially `"type": ["string",
      // "string", "string", ...]` but we're not here to judge
      return schema.type.every((t) => t === "string");
    }
    return false; // Invalid or non-string type
  }

  // Enum with only string values
  if ("enum" in schema) {
    return (
      Array.isArray(schema.enum) &&
      schema.enum.length > 0 &&
      schema.enum.every((val) => typeof val === "string")
    );
  }

  // String constant
  if ("const" in schema) {
    return typeof schema.const === "string";
  }

  // Schema combinations
  if ("allOf" in schema && Array.isArray(schema.allOf)) {
    // If any subschema validates only strings, then the overall schema validates only strings
    return schema.allOf.some((subschema) => validatesOnlyStrings(subschema));
  }

  if (
    ("anyOf" in schema && Array.isArray(schema.anyOf)) ||
    ("oneOf" in schema && Array.isArray(schema.oneOf))
  ) {
    const subschemas = (
      "anyOf" in schema ? schema.anyOf : schema.oneOf
    ) as unknown[];

    // All subschemas must validate only strings
    return (
      subschemas.length > 0 &&
      subschemas.every((subschema) => validatesOnlyStrings(subschema))
    );
  }

  // We're not going to try on this one, it's too complex - we just assume if it has a "not" key and hasn't matched one of the above checks, it's not a string schema.
  if ("not" in schema) {
    return false; // The not case can validate non-strings
  }

  if ("$ref" in schema && typeof schema.$ref === "string") {
    const ref = schema.$ref as string;
    const resolved = dereference(schema as Schema);
    if (resolved[ref]) {
      return validatesOnlyStrings(resolved[ref]);
    }
    return false;
  }

  // ignore recursive refs and other cases where type is omitted for now
  // ignore other cases for now where type is omitted

  return false;
}

// Re-export of the types used throughout langchain for json schema serialization.
// The plan is to eventually nix zod-to-json-schema altogether in place for
// zod v4 / a more standardized way of serializing validated inputs, so its re-exported
// here to remove the dependency on zod-to-json-schema in downstream packages until
// a determination is made.

export {
  type JsonSchema7Type,
  type JsonSchema7Type as JSONSchema,
  type JsonSchema7ArrayType,
  type JsonSchema7ObjectType,
  type JsonSchema7StringType,
  type JsonSchema7NumberType,
  type JsonSchema7NullableType,
} from "./zod-to-json-schema/index.js";

// Inlined from https://github.com/flexdinesh/browser-or-node
declare global {
  const Deno:
    | {
        version: {
          deno: string;
        };
        env: {
          get: (name: string) => string | undefined;
        };
      }
    | undefined;
}

export const isBrowser = () =>
  typeof window !== "undefined" && typeof window.document !== "undefined";

export const isWebWorker = () =>
  typeof globalThis === "object" &&
  globalThis.constructor &&
  globalThis.constructor.name === "DedicatedWorkerGlobalScope";

export const isJsDom = () =>
  (typeof window !== "undefined" && window.name === "nodejs") ||
  (typeof navigator !== "undefined" && navigator.userAgent.includes("jsdom"));

// Supabase Edge Function provides a `Deno` global object
// without `version` property
export const isDeno = () => typeof Deno !== "undefined";

// Mark not-as-node if in Supabase Edge Function
export const isNode = () =>
  typeof process !== "undefined" &&
  typeof process.versions !== "undefined" &&
  typeof process.versions.node !== "undefined" &&
  !isDeno();

export const getEnv = () => {
  let env: string;
  if (isBrowser()) {
    env = "browser";
  } else if (isNode()) {
    env = "node";
  } else if (isWebWorker()) {
    env = "webworker";
  } else if (isJsDom()) {
    env = "jsdom";
  } else if (isDeno()) {
    env = "deno";
  } else {
    env = "other";
  }

  return env;
};

export type RuntimeEnvironment = {
  library: string;
  libraryVersion?: string;
  runtime: string;
  runtimeVersion?: string;
};

let runtimeEnvironment: RuntimeEnvironment | undefined;

export function getRuntimeEnvironment(): RuntimeEnvironment {
  if (runtimeEnvironment === undefined) {
    const env = getEnv();

    runtimeEnvironment = {
      library: "langchain-js",
      runtime: env,
    };
  }
  return runtimeEnvironment;
}

export function getEnvironmentVariable(name: string): string | undefined {
  // Certain Deno setups will throw an error if you try to access environment variables
  // https://github.com/langchain-ai/langchainjs/issues/1412
  try {
    if (typeof process !== "undefined") {
      // eslint-disable-next-line no-process-env
      return process.env?.[name];
    } else if (isDeno()) {
      return Deno?.env.get(name);
    } else {
      return undefined;
    }
  } catch {
    return undefined;
  }
}

