import {
  _deepClone,
  _objectKeys,
  escapePathComponent,
  hasOwnProperty,
} from "./helpers.js";
import { applyPatch, Operation } from "./core.js";

export interface Observer<T> {
  object: T;
  patches: Operation[];
  unobserve: () => void;
  callback: (patches: Operation[]) => void;
}

var beforeDict = new WeakMap();

class Mirror {
  obj: any;
  observers: Map<Function, ObserverInfo> = new Map();
  value: Object | Array<any>;

  constructor(obj: Object) {
    this.obj = obj;
  }
}

class ObserverInfo {
  callback: Function;
  observer: ObserverInfo;

  constructor(callback: Function, observer: ObserverInfo) {
    this.callback = callback;
    this.observer = observer;
  }
}

function getMirror(obj: Object): Mirror {
  return beforeDict.get(obj);
}

function getObserverFromMirror(mirror: Mirror, callback): ObserverInfo {
  return mirror.observers.get(callback);
}

function removeObserverFromMirror(mirror: Mirror, observer): void {
  mirror.observers.delete(observer.callback);
}

/**
 * Detach an observer from an object
 */
export function unobserve<T>(root: T, observer: Observer<T>) {
  observer.unobserve();
}

/**
 * Observes changes made to an object, which can then be retrieved using generate
 */
export function observe<T>(
  obj: Object | Array<T>,
  callback?: (patches: Operation[]) => void
): Observer<T> {
  var patches = [];
  var observer;
  var mirror = getMirror(obj);

  if (!mirror) {
    mirror = new Mirror(obj);
    beforeDict.set(obj, mirror);
  } else {
    const observerInfo = getObserverFromMirror(mirror, callback);
    observer = observerInfo && observerInfo.observer;
  }

  if (observer) {
    return observer;
  }

  observer = {};

  mirror.value = _deepClone(obj);

  if (callback) {
    observer.callback = callback;
    observer.next = null;

    var dirtyCheck = () => {
      generate(observer);
    };
    var fastCheck = () => {
      clearTimeout(observer.next);
      observer.next = setTimeout(dirtyCheck);
    };
    if (typeof window !== "undefined") {
      //not Node
      window.addEventListener("mouseup", fastCheck);
      window.addEventListener("keyup", fastCheck);
      window.addEventListener("mousedown", fastCheck);
      window.addEventListener("keydown", fastCheck);
      window.addEventListener("change", fastCheck);
    }
  }
  observer.patches = patches;
  observer.object = obj;

  observer.unobserve = () => {
    generate(observer);
    clearTimeout(observer.next);
    removeObserverFromMirror(mirror, observer);

    if (typeof window !== "undefined") {
      window.removeEventListener("mouseup", fastCheck);
      window.removeEventListener("keyup", fastCheck);
      window.removeEventListener("mousedown", fastCheck);
      window.removeEventListener("keydown", fastCheck);
      window.removeEventListener("change", fastCheck);
    }
  };

  mirror.observers.set(callback, new ObserverInfo(callback, observer));

  return observer;
}

/**
 * Generate an array of patches from an observer
 */
export function generate<T>(
  observer: Observer<Object>,
  invertible = false
): Operation[] {
  var mirror = beforeDict.get(observer.object);

  _generate(mirror.value, observer.object, observer.patches, "", invertible);
  if (observer.patches.length) {
    applyPatch(mirror.value, observer.patches);
  }
  var temp = observer.patches;
  if (temp.length > 0) {
    observer.patches = [];
    if (observer.callback) {
      observer.callback(temp);
    }
  }
  return temp;
}

// Dirty check if obj is different from mirror, generate patches and update mirror
function _generate(mirror, obj, patches, path, invertible) {
  if (obj === mirror) {
    return;
  }

  if (typeof obj.toJSON === "function") {
    obj = obj.toJSON();
  }

  var newKeys = _objectKeys(obj);
  var oldKeys = _objectKeys(mirror);
  var changed = false;
  var deleted = false;

  //if ever "move" operation is implemented here, make sure this test runs OK: "should not generate the same patch twice (move)"

  for (var t = oldKeys.length - 1; t >= 0; t--) {
    var key = oldKeys[t];
    var oldVal = mirror[key];

    if (
      hasOwnProperty(obj, key) &&
      !(
        obj[key] === undefined &&
        oldVal !== undefined &&
        Array.isArray(obj) === false
      )
    ) {
      var newVal = obj[key];

      if (
        typeof oldVal == "object" &&
        oldVal != null &&
        typeof newVal == "object" &&
        newVal != null &&
        Array.isArray(oldVal) === Array.isArray(newVal)
      ) {
        _generate(
          oldVal,
          newVal,
          patches,
          path + "/" + escapePathComponent(key),
          invertible
        );
      } else {
        if (oldVal !== newVal) {
          changed = true;
          if (invertible) {
            patches.push({
              op: "test",
              path: path + "/" + escapePathComponent(key),
              value: _deepClone(oldVal),
            });
          }
          patches.push({
            op: "replace",
            path: path + "/" + escapePathComponent(key),
            value: _deepClone(newVal),
          });
        }
      }
    } else if (Array.isArray(mirror) === Array.isArray(obj)) {
      if (invertible) {
        patches.push({
          op: "test",
          path: path + "/" + escapePathComponent(key),
          value: _deepClone(oldVal),
        });
      }
      patches.push({
        op: "remove",
        path: path + "/" + escapePathComponent(key),
      });
      deleted = true; // property has been deleted
    } else {
      if (invertible) {
        patches.push({ op: "test", path, value: mirror });
      }
      patches.push({ op: "replace", path, value: obj });
      changed = true;
    }
  }

  if (!deleted && newKeys.length == oldKeys.length) {
    return;
  }

  for (var t = 0; t < newKeys.length; t++) {
    var key = newKeys[t];
    if (!hasOwnProperty(mirror, key) && obj[key] !== undefined) {
      patches.push({
        op: "add",
        path: path + "/" + escapePathComponent(key),
        value: _deepClone(obj[key]),
      });
    }
  }
}
/**
 * Create an array of patches from the differences in two objects
 */
export function compare(
  tree1: Object | Array<any>,
  tree2: Object | Array<any>,
  invertible = false
): Operation[] {
  var patches = [];
  _generate(tree1, tree2, patches, "", invertible);
  return patches;
}

import { ZodSchema } from "zod/v3";
import { Options, Targets } from "./Options.js";
import { parseDef } from "./parseDef.js";
import { JsonSchema7Type } from "./parseTypes.js";
import { getRefs } from "./Refs.js";
import { parseAnyDef } from "./parsers/any.js";

const zodToJsonSchema = <Target extends Targets = "jsonSchema7">(
  schema: ZodSchema<any>,
  options?: Partial<Options<Target>> | string
): (Target extends "jsonSchema7" ? JsonSchema7Type : object) & {
  $schema?: string;
  definitions?: {
    [key: string]: Target extends "jsonSchema7"
      ? JsonSchema7Type
      : Target extends "jsonSchema2019-09"
      ? JsonSchema7Type
      : object;
  };
} => {
  const refs = getRefs(options);

  let definitions =
    typeof options === "object" && options.definitions
      ? Object.entries(options.definitions).reduce(
          (acc: { [key: string]: JsonSchema7Type }, [name, schema]) => ({
            ...acc,
            [name]:
              parseDef(
                schema._def,
                {
                  ...refs,
                  currentPath: [...refs.basePath, refs.definitionPath, name],
                },
                true
              ) ?? parseAnyDef(refs),
          }),
          {}
        )
      : undefined;

  const name =
    typeof options === "string"
      ? options
      : options?.nameStrategy === "title"
      ? undefined
      : options?.name;

  const main =
    parseDef(
      schema._def,
      name === undefined
        ? refs
        : {
            ...refs,
            currentPath: [...refs.basePath, refs.definitionPath, name],
          },
      false
    ) ?? (parseAnyDef(refs) as JsonSchema7Type);

  const title =
    typeof options === "object" &&
    options.name !== undefined &&
    options.nameStrategy === "title"
      ? options.name
      : undefined;

  if (title !== undefined) {
    main.title = title;
  }

  if (refs.flags.hasReferencedOpenAiAnyType) {
    if (!definitions) {
      definitions = {};
    }

    if (!definitions[refs.openAiAnyTypeName]) {
      definitions[refs.openAiAnyTypeName] = {
        // Skipping "object" as no properties can be defined and additionalProperties must be "false"
        type: ["string", "number", "integer", "boolean", "array", "null"],
        items: {
          $ref:
            refs.$refStrategy === "relative"
              ? "1"
              : [
                  ...refs.basePath,
                  refs.definitionPath,
                  refs.openAiAnyTypeName,
                ].join("/"),
        },
      } as JsonSchema7Type;
    }
  }

  const combined: ReturnType<typeof zodToJsonSchema<Target>> =
    name === undefined
      ? definitions
        ? {
            ...main,
            [refs.definitionPath]: definitions,
          }
        : main
      : {
          $ref: [
            ...(refs.$refStrategy === "relative" ? [] : refs.basePath),
            refs.definitionPath,
            name,
          ].join("/"),
          [refs.definitionPath]: {
            ...definitions,
            [name]: main,
          },
        };

  if (refs.target === "jsonSchema7") {
    combined.$schema = "http://json-schema.org/draft-07/schema#";
  } else if (refs.target === "jsonSchema2019-09" || refs.target === "openAi") {
    combined.$schema = "https://json-schema.org/draft/2019-09/schema#";
  }

  if (
    refs.target === "openAi" &&
    ("anyOf" in combined ||
      "oneOf" in combined ||
      "allOf" in combined ||
      ("type" in combined && Array.isArray(combined.type)))
  ) {
    console.warn(
      "Warning: OpenAI may not support schemas with unions as roots! Try wrapping it in an object property."
    );
  }

  return combined;
};

export { zodToJsonSchema };

import { StandardJSONSchemaV1, StandardSchemaV1 } from "@standard-schema/spec";

/**
 * A schema that supports both runtime validation and JSON Schema generation. Any schema passed
 * to withStructuredOutput must satisfy both interfaces.
 */
// eslint-disable-next-line @typescript-eslint/no-explicit-any
export type SerializableSchema<Input = any, Output = Input> = StandardSchemaV1<
  Input,
  Output
> &
  StandardJSONSchemaV1<Input, Output>;

/**
 * Type guard for Standard Schema V1. Returns true if the value has a `~standard.validate`
 * interface, indicating it can validate unknown values at runtime (e.g. for parsing LLM output).
 */
// eslint-disable-next-line @typescript-eslint/no-explicit-any
export function isStandardSchema<Input = any, Output = Input>(
  schema: unknown
): schema is StandardSchemaV1<Input, Output> {
  return (
    (typeof schema === "object" || typeof schema === "function") &&
    schema !== null &&
    "~standard" in schema &&
    typeof schema["~standard"] === "object" &&
    schema["~standard"] !== null &&
    "validate" in schema["~standard"]
  );
}

/**
 * Type guard for Standard JSON Schema V1. Returns true if the value has a `~standard.jsonSchema`
 * interface, indicating it can be converted to a JSON Schema object (e.g. for sending as a tool
 * definition to an LLM).
 */
// eslint-disable-next-line @typescript-eslint/no-explicit-any
export function isStandardJsonSchema<Input = any, Output = Input>(
  schema: unknown
): schema is StandardJSONSchemaV1<Input, Output> {
  return (
    (typeof schema === "object" || typeof schema === "function") &&
    schema !== null &&
    "~standard" in schema &&
    typeof schema["~standard"] === "object" &&
    schema["~standard"] !== null &&
    "jsonSchema" in schema["~standard"]
  );
}

/**
 * Type guard for Standard Schema V1. Returns true if the value has a `~standard.validate` interface,
 * indicating it can validate unknown values at runtime (e.g. for parsing LLM output).
 */
// eslint-disable-next-line @typescript-eslint/no-explicit-any
export function isSerializableSchema<Input = any, Output = Input>(
  schema: unknown
): schema is SerializableSchema<Input, Output> {
  return isStandardSchema(schema) && isStandardJsonSchema(schema);
}

import { Client } from "langsmith";
import { getEnvironmentVariable } from "../utils/env.js";

let client: Client;

export const getDefaultLangChainClientSingleton = () => {
  if (client === undefined) {
    const clientParams =
      getEnvironmentVariable("LANGCHAIN_CALLBACKS_BACKGROUND") === "false"
        ? {
            // LangSmith has its own backgrounding system
            blockOnRootRunFinalization: true,
          }
        : {};
    client = new Client(clientParams);
